const orders = $input.all().map(item => item.json);
const grouped = {};
for (const o of orders) {
  if (!grouped[o.type_id]) grouped[o.type_id] = [];
  grouped[o.type_id].push(o);
}

const results = [];
for (const typeId in grouped) {
  const group = grouped[typeId];
  const sellOrders = group.filter(o => o.is_buy_order === false);
  const buyOrders = group.filter(o => o.is_buy_order === true);
  const bestSell = sellOrders.length ? Math.min(...sellOrders.map(o => o.price)) : null;
  const bestBuy = buyOrders.length ? Math.max(...buyOrders.map(o => o.price)) : null;
  const bestSellOrder = sellOrders.find(o => o.price === bestSell);
  const bestBuyOrder = buyOrders.find(o => o.price === bestBuy);

  results.push({
    json: {
      type_id: Number(typeId),
      jita_best_sell: bestSell,
      jita_best_sell_location: bestSellOrder?.location_id ?? null,
      jita_best_sell_volume: bestSellOrder?.volume_remain ?? null,
      jita_best_buy: bestBuy,
      jita_best_buy_location: bestBuyOrder?.location_id ?? null,
      jita_best_buy_volume: bestBuyOrder?.volume_remain ?? null
    }
  });
}
return results;

