const SALES_TAX = 0.045;
const BROKER_FEE = 0.03;

function calcRoute(buyPrice, sellPrice) {
  if (buyPrice == null || sellPrice == null) return null;
  const grossSpread = sellPrice - buyPrice;
  const netProfit = grossSpread - (sellPrice * SALES_TAX) - (sellPrice * BROKER_FEE);
  const netMarginPct = (netProfit / buyPrice) * 100;
  return { grossSpread, netProfit, netMarginPct };
}

const items = $input.all().map(item => item.json);
const results = [];

for (const it of items) {
  const routes = [
    { name: "Jita -> Amarr", buyPrice: it.jita_best_sell, sellPrice: it.amarr_best_sell,
      buyLoc: it.jita_best_sell_location, sellLoc: it.amarr_best_sell_location,
      availableVolume: it.jita_best_sell_volume },
    { name: "Amarr -> Jita", buyPrice: it.amarr_best_sell, sellPrice: it.jita_best_sell,
      buyLoc: it.amarr_best_sell_location, sellLoc: it.jita_best_sell_location,
      availableVolume: it.amarr_best_sell_volume }
  ];

  let best = null;
  for (const r of routes) {
    const calc = calcRoute(r.buyPrice, r.sellPrice);
    if (!calc) continue;
    if (!best || calc.netMarginPct > best.calc.netMarginPct) {
      best = { route: r, calc };
    }
  }
  if (!best) continue;

  const units = best.route.availableVolume ?? 0;
  const totalPotentialProfit = best.calc.netProfit * units;

  results.push({
    json: {
      type_id: it.type_id,
      route: best.route.name,
      buy_price: best.route.buyPrice,
      buy_location: best.route.buyLoc,
      sell_price: best.route.sellPrice,
      sell_location: best.route.sellLoc,
      units_available: units,
      gross_spread: best.calc.grossSpread,
      net_profit_per_unit: best.calc.netProfit,
      net_margin_pct: best.calc.netMarginPct,
      total_potential_profit: totalPotentialProfit
    }
  });
}

results.sort((a, b) => b.json.total_potential_profit - a.json.total_potential_profit);

return results;

const items = $input.all();
const cache = {};

const watchlist = $('Watchlist').all().map(i => i.json);
const ITEM_NAMES = Object.fromEntries(watchlist.map(w => [w.type_id, w.name]));

const getStationName = async (stationId) => {
  if (cache[stationId]) return cache[stationId];
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://esi.evetech.net/latest/universe/stations/${stationId}/`,
      qs: { datasource: 'tranquility' },
      json: true
    });
    cache[stationId] = res.name;
    return res.name;
  } catch (e) {
    return `Station ${stationId}`;
  }
};

const results = [];
for (const item of items) {
  const json = item.json;
  const buyName = await getStationName(json.buy_location);
  const sellName = await getStationName(json.sell_location);
  results.push({
    json: {
      ...json,
      item_name: ITEM_NAMES[json.type_id] || json.type_id,
      buy_station_name: buyName,
      sell_station_name: sellName
    }
  });
}

return results;

